#include <iostream>
#include <cstring>
#include <cstdio>

void concatenateStrings(const char* s1, const char* s2) {
    size_t len1 = strlen(s1);
    size_t len2 = strlen(s2);

    char* buffer = new char[len1 + len2 + 1];

    strcpy(buffer, s1);
    strcat(buffer, s2);

    printf("%s\n", buffer);

    delete[] buffer;
}

int main() {
    concatenateStrings("Hello", " World");
    concatenateStrings("", "World");
    concatenateStrings("Hello", "");
    concatenateStrings("", "");
    concatenateStrings("Programming is fun!", " Let's learn C++.");
    concatenateStrings("Path: C:\\Users\\", "Documents\\file.txt");
    return 0;
}
